UPDATE user_quota
SET used_space = used_space + #{size}
WHERE user_id = #{userId}
AND (
    total_quota = 9223372036854775807
    OR used_space + #{size} <= total_quota
)

UPDATE user_quota
SET used_space = GREATEST(used_space - #{size}, 0)
WHERE user_id = #{userId}

UPDATE user_quota
SET total_quota = #{newQuota}
WHERE total_quota != 9223372036854775807
